import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";

type ParseError = { _tag: "ParseError"; msg: string };
type MissingField = { _tag: "MissingField"; field: string };
type NotNumber = { _tag: "NotNumber"; got: unknown };

const parseJson = (s: string): E.Either<ParseError, unknown> =>
  E.tryCatch(() => JSON.parse(s), (u) => ({ _tag: "ParseError", msg: String(u) }));

const getField = (k: string) => (v: unknown): E.Either<MissingField, unknown> =>
  typeof v === "object" && v !== null && k in v
    ? E.right((v as Record<string, unknown>)[k])
    : E.left({ _tag: "MissingField", field: k });

const toNumber = (u: unknown): E.Either<NotNumber, number> =>
  typeof u === "number" ? E.right(u) : E.left({ _tag: "NotNumber", got: u });

export const parseUserId = (raw: string): string =>
  pipe(
    parseJson(raw),
    E.chainW(getField("id")),
    E.chainW(toNumber),
    E.mapLeft((e) => `bad input: ${e._tag}`),
    E.fold((msg) => msg, (n) => `id=${n}`),
  );
```

Each `E.chainW` widens the left type: `ParseError` → `ParseError | MissingField` → `ParseError | MissingField | NotNumber`. `E.mapLeft` flattens the union to a string, then `E.fold` collapses to a single `string` return.

