  pipe(
    checkFormat(raw),
    E.chainW(toDate),
    E.chainW(notFuture),
    E.mapLeft((e) => `reject:${e._tag}`),
    E.match((reason) => reason, (d) => `ok:${d.toISOString().slice(0, 10)}`),
