  pipe(
    E.right<never, string>(strip(raw)),
    E.chainW(length10),
    E.chainW(validChars),
    E.chainW(checksum),
    E.mapLeft((e): string => e._tag),
    E.match<string, string, IsbnResult>(
      (why) => ({ ok: false, why }),
      (isbn) => ({ ok: true, why: isbn }),
    ),
  );
