type BadPct = { _tag: "BadPct"; raw: string };
type BadBase = { _tag: "BadBase"; raw: string };
type Combined = { pct: number; base: number };

const parsePct = (s: string): E.Either<BadPct, number> => {
  const n = Number(s);
  return Number.isFinite(n) && n >= 0 && n <= 100 ? E.right(n) : E.left({ _tag: "BadPct", raw: s });
};

const parseBase = (s: string): E.Either<BadBase, number> => {
  const n = Number(s);
  return Number.isFinite(n) && n > 0 ? E.right(n) : E.left({ _tag: "BadBase", raw: s });
};

const round2 = (n: number): number => Math.round(n * 100) / 100;

export const discount = (pctStr: string, baseStr: string): string =>
  pipe(
    parsePct(pctStr),
    E.chainW((pct): E.Either<BadPct | BadBase, Combined> =>
      pipe(parseBase(baseStr), E.map((base) => ({ pct, base })))),
    E.map(({ pct, base }) => round2(base * (1 - pct / 100))),
    E.mapLeft((e) => `err:${e._tag}`),
    E.match((err) => err, (v) => `$${v.toFixed(2)}`),
  );
