import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";

type BadPrefix = { _tag: "BadPrefix" };
type BadLength = { _tag: "BadLength"; n: number };
type BadHex = { _tag: "BadHex" };

const hasHash = (s: string): E.Either<BadPrefix, string> =>
  s.startsWith("#") ? E.right(s.slice(1)) : E.left({ _tag: "BadPrefix" });

const expand = (s: string): E.Either<BadLength, string> => {
  if (s.length === 3) return E.right(s.split("").map((c) => c + c).join(""));
  if (s.length === 6) return E.right(s);
  return E.left({ _tag: "BadLength", n: s.length });
};

const validHex = (s: string): E.Either<BadHex, string> =>
  /^[0-9a-f]{6}$/i.test(s) ? E.right(s.toLowerCase()) : E.left({ _tag: "BadHex" });

const bump = (s: string): string => {
  const n = (h: string) => Math.min(255, Number.parseInt(h, 16) + 10).toString(16).padStart(2, "0");
  return `#${n(s.slice(0, 2))}${n(s.slice(2, 4))}${n(s.slice(4, 6))}`;
};

export const brighten = (raw: string): string =>
  pipe(
    hasHash(raw),
    E.chainW(expand),
    E.chainW(validHex),
    E.map(bump),
    E.mapLeft((e) => `#000000 /* ${e._tag} */`),
    E.fold((fallback) => fallback, (c) => c),
  );
```

