import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";

type NoAt = { _tag: "NoAt" };
type BadDomain = { _tag: "BadDomain" };
type EmptyPart = { _tag: "EmptyPart"; side: "local" | "domain" };

type Parts = { local: string; domain: string };

const splitAt = (s: string): E.Either<NoAt, Parts> => {
  const at = s.indexOf("@");
  return at < 0 ? E.left({ _tag: "NoAt" }) : E.right({ local: s.slice(0, at), domain: s.slice(at + 1) });
};

const bothNonEmpty = (p: Parts): E.Either<EmptyPart, Parts> => {
  if (p.local.length === 0) return E.left({ _tag: "EmptyPart", side: "local" });
  if (p.domain.length === 0) return E.left({ _tag: "EmptyPart", side: "domain" });
  return E.right(p);
};

const domainHasDot = (p: Parts): E.Either<BadDomain, Parts> =>
  p.domain.includes(".") ? E.right(p) : E.left({ _tag: "BadDomain" });

export const parseEmail = (raw: string): string =>
  pipe(
    splitAt(raw.trim()),
    E.chainW(bothNonEmpty),
    E.chainW(domainHasDot),
    E.map(({ local, domain }) => `${local.toLowerCase()}@${domain.toLowerCase()}`),
    E.mapLeft((e) => `bad email: ${e._tag}`),
    E.fold((err) => err, (email) => email),
  );
```

The widened left `NoAt | EmptyPart | BadDomain` is what makes `E.chainW` worth reaching for over plain `E.chain`.

