  pipe(
    toNum("approved")(approved),
    E.chainW((a) =>
      pipe(
        toNum("requested")(requested),
        E.chainW(withinLimit(a)),
      ),
    ),
    E.mapLeft((e) => e._tag === "BadNumber" ? `parse fail: ${e.field}` : `denied: ${e.requested}>${e.approved}`),
    E.fold((err) => err, (rem) => `remaining: ${rem}`),
  );
