  const n = Number.parseInt(raw, 10);
  return Number.isFinite(n) ? E.right(n) : E.left({ _tag: "NotInt", key });
};

const between = (key: string, lo: number, hi: number) => (n: number): E.Either<OutOfRange, number> =>
  n >= lo && n <= hi ? E.right(n) : E.left({ _tag: "OutOfRange", key, n });

export const paging = (qs: URLSearchParams): Paging =>
  pipe(
    readInt(qs, "page"),
    E.chainW(between("page", 1, Number.MAX_SAFE_INTEGER)),
    E.chainW((page): E.Either<Missing | NotInt | OutOfRange, Paging> =>
      pipe(readInt(qs, "size"), E.chainW(between("size", 1, 100)), E.map((size) => ({ page, size })))),
    E.mapLeft((_e): Paging => ({ page: 1, size: 20 })),
    E.fold((def) => def, (p) => p),
  );
```

