  const ps = s.split(".");
  return ps.length === 4 ? E.right(ps) : E.left({ _tag: "BadShape", parts: ps.length });
};

const toOctets = (parts: ReadonlyArray<string>): E.Either<BadOctet, ReadonlyArray<number>> => {
  const out: number[] = [];
  for (const p of parts) {
    const n = Number.parseInt(p, 10);
    if (!Number.isFinite(n) || n < 0 || n > 255) return E.left({ _tag: "BadOctet", raw: p });
    out.push(n);
  }
  return E.right(out);
};

const pack = (octets: ReadonlyArray<number>): number =>
  ((octets[0] << 24) | (octets[1] << 16) | (octets[2] << 8) | octets[3]) >>> 0;

