  pipe(
    fourParts(raw),
    E.chainW(toOctets),
    E.map(pack),
    E.mapLeft((e) => `invalid ipv4 (${e._tag})`),
    E.fold((err) => err, (n) => n.toString(16).padStart(8, "0")),
  );
