    : E.left({ _tag: "BadOp", got: s });

const toSymbol = (op: Op): Symbol =>
  op === "add" ? "+" : op === "sub" ? "-" : op === "mul" ? "*" : "/";

const guardDiv = (op: Op, rhs: number): E.Either<DivByZero, Op> =>
  op === "div" && rhs === 0 ? E.left({ _tag: "DivByZero" }) : E.right(op);

export const apply = (opStr: string, lhs: number, rhs: number): string =>
  pipe(
    parseOp(opStr),
    E.chainW((op) => guardDiv(op, rhs)),
    E.map((op) => {
      const s = toSymbol(op);
      const result = op === "add" ? lhs + rhs : op === "sub" ? lhs - rhs : op === "mul" ? lhs * rhs : lhs / rhs;
      return `${lhs}${s}${rhs}=${result}`;
    }),
    E.mapLeft((e) => `err:${e._tag}`),
    E.fold((err) => err, (expr) => expr),
  );
```

`E.chainW` widens `BadOp` to `BadOp | DivByZero`; both are flattened to a single `err:<tag>` string by `E.mapLeft`.

```ts
import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";

interface Rollout { enabled: true; rolloutPct: number }

type ParseErr = { _tag: "ParseErr"; msg: string };
type Disabled = { _tag: "Disabled" };
type BadPct = { _tag: "BadPct"; got: unknown };

const parse = (s: string): E.Either<ParseErr, unknown> =>
  E.tryCatch(() => JSON.parse(s), (u) => ({ _tag: "ParseErr", msg: String(u) }));

const enabled = (u: unknown): E.Either<Disabled, Record<string, unknown>> => {
  if (typeof u === "object" && u !== null && (u as { enabled?: unknown }).enabled === true) {
    return E.right(u as Record<string, unknown>);
  }
  return E.left({ _tag: "Disabled" });
};

const readPct = (o: Record<string, unknown>): E.Either<BadPct, Rollout> => {
  const p = o.rolloutPct;
  return typeof p === "number" && p >= 0 && p <= 100
    ? E.right({ enabled: true, rolloutPct: p })
    : E.left({ _tag: "BadPct", got: p });
};

export const loadRollout = (raw: string): E.Either<string, Rollout> =>
  pipe(
    parse(raw),
    E.chainW(enabled),
    E.chainW(readPct),
    E.mapLeft((e) => `rollout:${e._tag}`),
    E.match(
      (reason) => E.left<string, Rollout>(reason),
      (r) => E.right<string, Rollout>(r),
    ),
  );
```

The widened `ParseErr | Disabled | BadPct` makes every failure mode explicit in the type of the intermediate; `E.mapLeft` then normalises to a single reason string.

Compose validators with `pipe(first, E.chainW(second), E.chainW(third), ...)`. `E.chainW` is the widening variant — it unions new error types onto the left as you go, so the final `E.mapLeft` sees the whole set.

```ts
import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";

type Sub = "start" | "stop" | "status";

type BadArity = { _tag: "BadArity"; got: number };
type BadSub = { _tag: "BadSub"; got: string };
type BadNum = { _tag: "BadNum"; raw: string };

const two = (argv: ReadonlyArray<string>): E.Either<BadArity, [string, string]> =>
  argv.length === 2 ? E.right([argv[0], argv[1]]) : E.left({ _tag: "BadArity", got: argv.length });

const sub = ([s, n]: [string, string]): E.Either<BadSub, [Sub, string]> =>
  s === "start" || s === "stop" || s === "status" ? E.right([s, n]) : E.left({ _tag: "BadSub", got: s });

const num = ([s, n]: [Sub, string]): E.Either<BadNum, [Sub, number]> => {
  const x = Number(n);
  return Number.isFinite(x) ? E.right([s, x]) : E.left({ _tag: "BadNum", raw: n });
};

export const parseArgs = (argv: ReadonlyArray<string>): string =>
  pipe(
    two(argv),
    E.chainW(sub),
    E.chainW(num),
    E.mapLeft((e) => `usage error: ${e._tag}`),
    E.match((err) => err, ([s, n]) => `${s}(${n})`),
  );
```

```ts
import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";

interface Bucket { remaining: number; resetAt: number }

type BadRemaining = { _tag: "BadRemaining"; raw: string };
type BadReset = { _tag: "BadReset"; raw: string };
type ResetInPast = { _tag: "ResetInPast"; resetAt: number };

const parseIntNN = (raw: string): E.Either<BadRemaining, number> => {
  const n = Number.parseInt(raw, 10);
  return Number.isFinite(n) && n >= 0 ? E.right(n) : E.left({ _tag: "BadRemaining", raw });
};

const parseMs = (raw: string): E.Either<BadReset, number> => {
  const n = Number.parseInt(raw, 10);
  return Number.isFinite(n) ? E.right(n) : E.left({ _tag: "BadReset", raw });
};

const future = (now: number) => (resetAt: number): E.Either<ResetInPast, number> =>
  resetAt > now ? E.right(resetAt) : E.left({ _tag: "ResetInPast", resetAt });

export const parseBucket = (remainingRaw: string, resetRaw: string, now: number): E.Either<string, Bucket> =>
  pipe(
    parseIntNN(remainingRaw),
    E.chainW((remaining) =>
      pipe(
        parseMs(resetRaw),
        E.chainW(future(now)),
        E.map((resetAt) => ({ remaining, resetAt })),
      ),
    ),
    E.mapLeft((e) => e._tag),
    E.match(
      (tag) => E.left<string, Bucket>(tag),
      (b) => E.right<string, Bucket>(b),
    ),
  );
```

The widened left `BadRemaining | BadReset | ResetInPast` is visible at the `E.mapLeft` boundary — where we project to a discriminator and rewrap for callers.
